import logo from './logo.svg';
import './App.css';

function App() {
  return (
    <div className="App">
      <Welcome/>
      <Welcome/>
      <Welcome/>
      <header className="App-header">
        <img src={logo} className="App-logo" alt="logo" />
        <p>
          Edit <code>src/App.js</code> and save to reload.
        </p>
        <a
          className="App-link"
          href="https://reactjs.org"
          target="_blank"
          rel="noopener noreferrer"
        >
          Hola soy fer este es mi primer programa en React
        </a>
      </header>
    </div>
  );
}

function Welcome(){
  return (
    <h1> hola este es mi primer componente en React</h1>
  );
}

export default App;
